import React, { useState } from "react";
import { Link } from "react-router-dom";

export default function Register() {
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [birthPlace, setBirthPlace] = useState("");
  const [birthDate, setBirthDate] = useState("");
  const [role, setRole] = useState("");

  const [buttonText, setButtonText] = useState("Create Account");

  const handleSubmit = (e) => {
    e.preventDefault();
  };

  return (
    <div className="relative w-full min-h-screen bg-black flex items-center justify-center">
      <div className="w-full max-w-md p-6 bg-black/50 rounded-2xl border border-green-500/30">
        <h2 className="text-3xl text-white text-center mb-6">Register</h2>

        <form onSubmit={handleSubmit}>
          <input type="text" placeholder="First Name" value={firstName} onChange={(e)=>setFirstName(e.target.value)} className="custom-input mb-4" />
          <input type="text" placeholder="Last Name" value={lastName} onChange={(e)=>setLastName(e.target.value)} className="custom-input mb-4" />
          <input type="email" placeholder="Email" value={email} onChange={(e)=>setEmail(e.target.value)} className="custom-input mb-4" />
          <input type="text" placeholder="Birth Place" value={birthPlace} onChange={(e)=>setBirthPlace(e.target.value)} className="custom-input mb-4" />
          <input type="date" value={birthDate} onChange={(e)=>setBirthDate(e.target.value)} className="custom-input mb-4" />
          <input type="password" placeholder="Password" value={password} onChange={(e)=>setPassword(e.target.value)} className="custom-input mb-4" />

          <button className="w-full bg-green-600 text-white py-2 rounded-xl">
            {buttonText}
          </button>

          <p className="text-white text-sm mt-4 text-center">
            Already have an account?{" "}
            <Link to="/auth/login" className="text-green-400">
              Sign In
            </Link>
          </p>
        </form>
      </div>

      <style>{`
        .custom-input {
          width: 100%;
          padding: 10px 0;
          background: transparent;
          border: none;
          border-bottom: 2px solid #2e7d32;
          color: white;
          outline: none;
          box-shadow: none;
        }

        .custom-input:focus {
          border-bottom: 2px solid #00d8d0;
          outline: none;
          box-shadow: none;
        }

        input:focus,
        input:focus-visible {
          outline: none !important;
          box-shadow: none !important;
        }
      `}</style>
    </div>
  );
}
